sql:
SELECT SUM(engagement_value) AS total_likes
FROM user_engagement
WHERE content_id = 1 AND engagement_type = 'like';

external_knowledge:
- 'Torchbearers' refers to active and verified users who are also content creators;
- 'lit the fire of creativity' refers to having created content;
- 'had their sparks approved' refers to having at least one approved content.

sql:
SELECT engagement_type, engagement_value
FROM user_engagement
WHERE engagement_id = 1;
